pub fn resolve_map<F>(&self, mut leaf_to_output_fn: F) -> Result<L, ()>
where
    F: FnMut(&L) -> Result<L, ()>,
{
    self.resolve_internal(&mut leaf_to_output_fn)
}

fn resolve_internal<F>(&self, leaf_to_output_fn: &mut F) -> Result<L, ()>
