            result.map(|v| v.neg())?;
            Ok(result)
        },
        Self::Invert(child) => {
            let mut result = child.resolve_internal(leaf_to_output_fn)?;
            result.map(|v| 1.0 / v)?;
            Ok(result)
        },
        Self::Sum(children) => {
            let mut result = children[0].resolve_internal(leaf_to_output_fn)?;

